const chicagoTimeZone = 'America/Chicago';

// Use DateTime.now() instead of today() in the Code Node
const threshold = DateTime.now().setZone(chicagoTimeZone).startOf('day');

console.log('Chicago Threshold:', threshold.toString());

// Filter the incoming items
return items.filter(item => {
  try {
    const ts = item.json.Timestamp;

    if (!ts) return false;

    // Parse the ISO string (e.g., "2026-04-02T22:46:58.556+08:00")
    const itemDate = DateTime.fromISO(ts).setZone(chicagoTimeZone);

    // Keep items where the date is greater than or equal to Chicago's start of day
    return itemDate >= threshold;

  } catch (error) {
    // This prevents one bad row from stopping the whole workflow
    return false; 
  }
});

// Get all users from the incoming items
const users = items.map(item => item.json.User);

// Use a Set to store only unique email addresses
const uniqueUsers = new Set(users);

// The number of items in the array is the total number of requests
const totalRequests = items.length;

// Return the result as a single object for the next node
return [
  {
    json: {
      unique_user_count: uniqueUsers.size,
      total_requests: totalRequests,
      unique_users_list: Array.from(uniqueUsers) // Optional: list of the actual users
    }
  }
];

